1	import { describe, it, expect, vi } from "vitest";
2	import { screen } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import Portfolio from "@/routes/Portfolio";
5	import * as api from "@/lib/api/client";
6	
7	vi.mock("@/lib/api/client");
8	
9	describe("Portfolio", () => {
10	  it("renders account prompt when no session configured", () => {
11	    vi.mocked(api.listMarkets).mockResolvedValue({
12	      markets: [],
13	      count: 0,
14	      meta: { apiVersion: "1.0", timestamp: "2026-04-09T00:00:00Z" },
15	    });
16	
17	    renderWithProviders(<Portfolio />);
18	    expect(screen.getByText(/Set your Account ID/)).toBeInTheDocument();
19	  });
20	});
21

1	import { useMemo } from "react";
2	import { useSession } from "@/features/session/context";
3	import { useAccountRisk, useMarkets } from "@/lib/query/hooks";
4	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
5	import { Link } from "react-router-dom";
6	
7	export default function Portfolio() {
8	  const { session, isConfigured } = useSession();
9	  const { data, isLoading, error } = useAccountRisk(session.accountId);
10	  const marketsQuery = useMarkets();
11	  const marketTitles = useMemo(() => {
12	    const map = new Map<string, string>();
13	    marketsQuery.data?.markets.forEach((m) => map.set(m.id, m.title));
14	    return map;
15	  }, [marketsQuery.data]);
16	
17	  if (!isConfigured) {
18	    return (
19	      <div style={{ textAlign: "center", padding: "var(--space-xl)", color: "var(--color-text-muted)" }}>
20	        Set your Account ID in the header to view your portfolio.
21	      </div>
22	    );
23	  }
24	
25	  if (isLoading) return <LoadingPage />;
26	  if (error) return <ErrorMessage message="Account not found or no positions yet." />;
27	  if (!data) return null;
28	
29	  const risk = data.account.risk;
30	  const cap = risk.capacityIndicators;
31	  const healthColor = cap.status === "healthy" ? "var(--color-success)"
32	    : cap.status === "warning" ? "var(--color-warning)"
33	    : "var(--color-danger)";
34	
35	  return (
36	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
37	      <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>Portfolio</h1>
38	
39	      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: "var(--space-md)" }}>
40	        <MetricCard label="Limit" value={cap.limit.toFixed(2)} />
41	        <MetricCard label="Available" value={cap.available.toFixed(2)} />
42	        <MetricCard label="Consumed" value={cap.consumed.toFixed(2)} />
43	        <MetricCard label="Utilization" value={`${(cap.utilization * 100).toFixed(1)}%`} />
44	        <MetricCard label="Health" value={cap.status} color={healthColor} />
45	        <MetricCard label="Min Asset (Overall)" value={risk.minAssets.overall.toFixed(2)} />
46	      </div>
47	      {risk.updatedAt && (
48	        <div style={{ fontSize: "0.7rem", color: "var(--color-text-muted)" }}>
49	          Last updated: {new Date(risk.updatedAt).toLocaleString()}
50	        </div>
51	      )}
52	
53	      <div>
54	        <h2 style={{ fontSize: "1.1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>Per-Market Positions</h2>
55	        {risk.minAssets.markets.length === 0 ? (
56	          <span style={{ color: "var(--color-text-muted)" }}>No positions.</span>
57	        ) : (
58	          <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
59	            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
60	              <thead>
61	                <tr style={{ background: "var(--color-bg-hover)" }}>
62	                  <th style={thStyle}>Market</th>
63	                  <th style={thStyle}>Min Asset</th>
64	                  <th style={thStyle}>Utilization</th>
65	                  <th style={thStyle}>Trades</th>
66	                </tr>
67	              </thead>
68	              <tbody>
69	                {risk.minAssets.markets.map((mr) => (
70	                  <tr key={mr.marketId} style={{ borderTop: "1px solid var(--color-border)" }}>
71	                    <td style={tdStyle}>
72	                      <Link to={`/markets/${mr.marketId}`}>
73	                        {marketTitles.get(mr.marketId) ?? mr.marketId}
74	                      </Link>
75	                    </td>
76	                    <td style={tdStyle}>{mr.minAsset.toFixed(2)}</td>
77	                    <td style={tdStyle}>{(mr.utilization * 100).toFixed(1)}%</td>
78	                    <td style={tdStyle}>{mr.commandCount}</td>
79	                  </tr>
80	                ))}
81	              </tbody>
82	            </table>
83	          </div>
84	        )}
85	      </div>
86	    </div>
87	  );
88	}
89	
90	function MetricCard({ label, value, color }: { label: string; value: string; color?: string }) {
91	  return (
92	    <div style={{
93	      padding: "var(--space-md)",
94	      borderRadius: "var(--radius-md)",
95	      background: "var(--color-bg-surface)",
96	      border: "1px solid var(--color-border)",
97	    }}>
98	      <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)", marginBottom: "var(--space-xs)" }}>{label}</div>
99	      <div style={{ fontSize: "1.25rem", fontWeight: 600, color: color ?? "var(--color-text)" }}>{value}</div>
100	    </div>
101	  );
102	}
103	
104	const thStyle: React.CSSProperties = { textAlign: "left", padding: "6px 12px", fontWeight: 500 };
105	const tdStyle: React.CSSProperties = { padding: "6px 12px" };
106

1	import { createContext, useContext, useState, useCallback, type ReactNode } from "react";
2	import type { Session } from "@/lib/api/types";
3	
4	const STORAGE_KEY = "bayes-session";
5	
6	function loadSession(): Session {
7	  try {
8	    const raw = localStorage.getItem(STORAGE_KEY);
9	    if (raw) {
10	      const parsed = JSON.parse(raw) as Session;
11	      return { accountId: parsed.accountId ?? "", agentId: parsed.agentId ?? "" };
12	    }
13	  } catch {
14	    // ignore corrupt storage
15	  }
16	  return { accountId: "", agentId: "" };
17	}
18	
19	function saveSession(session: Session): void {
20	  localStorage.setItem(STORAGE_KEY, JSON.stringify(session));
21	}
22	
23	interface SessionContextValue {
24	  session: Session;
25	  setAccountId: (id: string) => void;
26	  setAgentId: (id: string) => void;
27	  isConfigured: boolean;
28	}
29	
30	const SessionContext = createContext<SessionContextValue | null>(null);
31	
32	export function SessionProvider({ children }: { children: ReactNode }) {
33	  const [session, setSession] = useState<Session>(loadSession);
34	
35	  const setAccountId = useCallback((accountId: string) => {
36	    setSession((prev) => {
37	      const next = { ...prev, accountId };
38	      saveSession(next);
39	      return next;
40	    });
41	  }, []);
42	
43	  const setAgentId = useCallback((agentId: string) => {
44	    setSession((prev) => {
45	      const next = { ...prev, agentId };
46	      saveSession(next);
47	      return next;
48	    });
49	  }, []);
50	
51	  return (
52	    <SessionContext.Provider
53	      value={{ session, setAccountId, setAgentId, isConfigured: session.accountId.length > 0 }}
54	    >
55	      {children}
56	    </SessionContext.Provider>
57	  );
58	}
59	
60	export function useSession(): SessionContextValue {
61	  const ctx = useContext(SessionContext);
62	  if (!ctx) throw new Error("useSession must be used within SessionProvider");
63	  return ctx;
64	}
65

1	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
2	import * as api from "@/lib/api/client";
3	import type {
4	  AnalyticsInterval,
5	  ProbabilityEditPayload,
6	  EventTradePayload,
7	  CommentPayload,
8	  MarketCommentsResponse,
9	  Session,
10	  MarketListFilters,
11	} from "@/lib/api/types";
12	import { marketListQueryKey } from "@/lib/marketListFilters";
13	
14	export const queryKeys = {
15	  marketLists: () => ["markets", "list"] as const,
16	  markets: (filters: MarketListFilters = {}) =>
17	    [...queryKeys.marketLists(), marketListQueryKey(filters)] as const,
18	  market: (id: string) => ["markets", id] as const,
19	  marketEvents: (id: string) => ["markets", id, "events"] as const,
20	  marketComments: (id: string) => ["markets", id, "comments"] as const,
21	  engineStats: (id: string) => ["markets", id, "engine-stats"] as const,
22	  marketAnalytics: (id: string, interval?: AnalyticsInterval) =>
23	    [...queryKeys.market(id), "analytics", { interval: interval ?? null }] as const,
24	  account: (id: string) => ["accounts", id] as const,
25	  accountRisk: (id: string) => [...queryKeys.account(id), "risk"] as const,
26	  accountPnl: (id: string) => [...queryKeys.account(id), "pnl"] as const,
27	  health: () => ["health"] as const,
28	  serviceIndex: () => ["service-index"] as const,
29	};
30	
31	function createEmptyMarketCommentsResponse(marketId: string): MarketCommentsResponse {
32	  return {
33	    marketId,
34	    comments: [],
35	    pagination: {
36	      fromSeq: 0,
37	      limit: 0,
38	      returned: 0,
39	      nextFromSeq: null,
40	    },
41	    meta: {
42	      apiVersion: "unknown",
43	      timestamp: "1970-01-01T00:00:00.000Z",
44	    },
45	  };
46	}
47	
48	export function useMarkets(filters: MarketListFilters = {}) {
49	  return useQuery({
50	    queryKey: queryKeys.markets(filters),
51	    queryFn: () => api.listMarkets(filters),
52	    refetchInterval: 5000,
53	  });
54	}
55	
56	export function useMarket(marketId: string, opts?: { enabled?: boolean }) {
57	  return useQuery({
58	    queryKey: queryKeys.market(marketId),
59	    queryFn: () => api.getMarket(marketId),
60	    refetchInterval: 5000,
61	    enabled: opts?.enabled ?? true,
62	  });
63	}
64	
