  accountRisk: (id: string) => [...queryKeys.account(id), "risk"] as const,
  // ... more query keys
};

export function useMarkets(filters: MarketListFilters = {}) {
  return useQuery({
    queryKey: queryKeys.markets(filters),
    queryFn: () => api.listMarkets(filters),
    refetchInterval: 5000,
  });
}

export function useAccountRisk(accountId: string) {
  return useQuery({
    queryKey: queryKeys.accountRisk(accountId),
    queryFn: () => api.getAccountRisk(accountId),
    enabled: accountId.length > 0,
  });
}
```

**Return types for these hooks:**
- `useAccountRisk(accountId)` returns a React Query `UseQueryResult` with:
  - `data: AccountRiskResponse | undefined`
  - `isLoading: boolean`
  - `error: Error | null`
  - `isSuccess: boolean`
  - `isError: boolean`

- `useMarkets()` returns same structure with:
  - `data: MarketListResponse | undefined`

