### 7. **Test Helper Setup**
**Path:** `/tmp/temporal-worktrees/task-task-portfolio-coverage-001/frontend/src/__tests__/helpers.tsx`

```typescript
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { MemoryRouter } from "react-router-dom";
import { SessionProvider } from "@/features/session/context";
import { routerFuture } from "@/app/routerFuture";
import { render, type RenderOptions } from "@testing-library/react";
import type { ReactElement, ReactNode } from "react";

function createTestQueryClient() {
  return new QueryClient({
    defaultOptions: {
      queries: { retry: false, gcTime: 0 },
      mutations: { retry: false },
    },
  });
}

function TestProviders({
  children,
  initialEntries,
}: {
  children: ReactNode;
  initialEntries?: string[];
}) {
  const qc = createTestQueryClient();
  return (
    <QueryClientProvider client={qc}>
      <SessionProvider>
        <MemoryRouter future={routerFuture} initialEntries={initialEntries}>
          {children}
        </MemoryRouter>
      </SessionProvider>
    </QueryClientProvider>
  );
}

export function renderWithProviders(
  ui: ReactElement,
  options?: Omit<RenderOptions, "wrapper"> & { route?: string; initialEntries?: string[] },
) {
  const { route, initialEntries, ...renderOptions } = options ?? {};

  function Wrapper({ children }: { children: ReactNode }) {
    return (
      <TestProviders initialEntries={initialEntries ?? (route ? [route] : undefined)}>
        {children}
      </TestProviders>
    );
  }

  return render(ui, { wrapper: Wrapper, ...renderOptions });
}
```

---

### 8. **Type Definitions for Data Structures**

**AccountRiskResponse** (from `/tmp/temporal-worktrees/task-task-portfolio-coverage-001/frontend/src/lib/api/types.ts`):
```typescript
export interface AccountRiskResponse {
  account: {
    id: string;
    risk: {
      minAssets: {
        overall: number;
        markets: MarketRisk[];
      };
      capacityIndicators: CapacityIndicators;
      updatedAt: string;
    };
  };
  meta: Meta;
}

export interface MarketRisk {
  marketId: string;
  minAsset: number;
  capacityConsumed: number;
  utilization: number;
  commandCount: number;
  lastOrderId: string;
  lastCommandId: string;
  updatedAt: string;
}

export interface CapacityIndicators {
  limit: number;
  available: number;
  consumed: number;
  utilization: number;
  status: "healthy" | "warning" | "critical";
}

export interface MarketListResponse {
  markets: MarketSummary[];
  count: number;
  meta: Meta;
}

export interface MarketSummary {
  id: string;
  title: string;
  status: MarketStatus;
  liquidity: number;
  volume: number;
  expires_at: string;
}

export interface Session {
  accountId: string;
  agentId: string;
}
```

---

### Summary of Key Testing Considerations:

1. **Portfolio component uses 2 main hooks:**
   - `useSession()` - context-based, returns `{ session, isConfigured, ... }`
   - `useAccountRisk(accountId)` - React Query hook with loading/error states
   - `useMarkets()` - React Query hook for market list

2. **Main rendering branches to test:**
   - Not configured (no accountId)
   - Loading (isLoading = true)
   - Error (error exists)
   - Success with data (MetricCard rendering + table)
   - Empty positions (no markets in array)

3. **Assertion patterns used in codebase:**
   - `screen.getByText()` - text content
   - `screen.getByRole()` - semantic HTML
   - `screen.getAllByText()` - multiple matches
   - `waitFor()` - async queries
   - `expect(...).toHaveBeenCalledWith()` - mock verification

4. **MetricCard test assertions:**
   - Labels: "Limit", "Available", "Consumed", "Utilization", "Health", "Min Asset (Overall)"
   - Values as formatted strings (e.g., "100.50", "75.3%", "healthy")
   - Color styling for health status

All the complete code has been provided above for your thorough review of the Portfolio route test setup!

